customCSS:
/* Dracula Theme */
@import url('https://fonts.googleapis.com/css2?family=Fira+Sans:wght@300;400;500;600;700&family=Fira+Code&display=swap');

.cyber-glow {
  background: 
    radial-gradient(ellipse 600px 400px at 20% 10%, rgba(189, 147, 249, 0.22), transparent),
    radial-gradient(ellipse 500px 350px at 80% 80%, rgba(255, 121, 198, 0.15), transparent);
}

.cyber-particles { display: none; }

.stat-card {
  border: 1px solid rgba(189, 147, 249, 0.15);
  background: rgba(68, 71, 90, 0.8);
}

.stat-card::before {
  background: linear-gradient(90deg, #bd93f9, #ff79c6, #8be9fd);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(255, 121, 198, 0.3);
  box-shadow: 0 4px 20px rgba(189, 147, 249, 0.15);
}

.stat-value {
  text-shadow: 0 0 15px currentColor;
}

.celebration-title {
  background: linear-gradient(135deg, #bd93f9, #ff79c6);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
}

.miner-card, .health-card, .lifetime-card {
  background: rgba(68, 71, 90, 0.6);
  border: 1px solid rgba(189, 147, 249, 0.1);
}

.miner-card:hover {
  border-color: rgba(80, 250, 123, 0.2);
}
